package exercicios.oop.java.domain;public class Calculator {     public int somaNumeros(int num1, int num2){         return num1 + num2;     }     public int subtrairNumeros(int num1, int num2){         return num1 - num2;     }     public int multiplyNums(int num1, int num2){         return num1 * num2;     }     public double divisaoNums(int num1, int num2){         return (double) num1 / num2;     }}